// نقوم بجلب النص الخارج من نود الـ AI Agent
// ملاحظة: تأكد من تغيير اسم الـ Node إذا كان مختلفاً لديك (مثلاً 'AI Agent')
const rawText = $input.item.json.output || $input.item.json.text;
const uniqueId = Math.floor(1000 + Math.random() * 9000);
try {
    // تحويل النص إلى كائن JSON صالح
    const parsedData = JSON.parse(rawText.trim());

    // إرجاع البيانات بشكل منظم للنودز التالية
    return [{
        json: {
          id: uniqueId,
            action_type: parsedData.action_type || "unclear",
            delete_search_term: parsedData.delete_search_term || null,
            send_email: parsedData.send_email || false,

            // بيانات الجدول (إذا كانت عملية تحليل)
            decision: parsedData.decision_data ? parsedData.decision_data.decision : null,
            classification:parsedData.decision_data ?
              parsedData.decision_data.decision: null,
            time: parsedData.decision_data ? parsedData.decision_data.time : null,
            priority: parsedData.decision_data ? parsedData.decision_data.priority : null,
            description: parsedData.decision_data ? parsedData.decision_data.description : null
        }
    }];

} catch (error) {
    // في حال حدوث خطأ غير متوقع في التحليل، يتم تمرير الخطأ لتجنب توقف الـ Workflow
    return [{
        json: {
            action_type: "unclear",
            error: "فشل في تحليل الـ JSON: " + error.message,
            raw_output: rawText
        }
    }];
}

